dn.com/dms/image/v2/C4E0BAQG5Akuqhw2Xpg/company-logo_200_200/company-logo_200_200/0/1652728102055/utah_techu_logo?e=1778112000&v=beta&t=Axq-bAExUSq0EkHuzfG0vARIwWx8_ITPtVB8pn1LBCs", "educations/0/period/endedOn/month": "12", "educations/0/period/endedOn/year": "2024", "educations/0/period/startedOn/month": "6", "educations/0/period/startedOn/year": "2024", "educations/0/subtitle": "Short-Term Rental Management", "educations/0/title": "Utah Tech University", "educations/1/companyId": "17197", "educations/1/companyLink1": "https://www.linkedin.com/school/assumption-university/", "educations/1/companyUrn": "urn:li:fsd_company:17197", "educations/1/logo": "https://media.licdn.com/dms/image/v2/C4E0BAQFa3Yd2PfPzmg/company-logo_200_200/company-logo_200_200/0/1631320346714?e=1778112000&v=beta&t=s2A_W-U56Mg6Q3Hcewn8WsW6sbRkCzgzxuAhszHpt08", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "2013", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "2009", "educations/1/subtitle": "Bachelor of Business Administration (B.B.A.), International Business Management (Major) and Finance and Banking (Minor)", "educations/1/title": "Assumption University", "email": "sandy.nitkitsomboon@fazwaz.com", "experiences/0/companyId": "6443961", "experiences/0/companyIndustry": "Real Estate", "experiences/0/companyLink1": "https://www.linkedin.com/company/fazwaz/", "experiences/0/companyName": "FazWaz", "experiences/0/companySize": "501-1000", "experiences/0/companyUrn": "urn:li:fsd_company:6443961", "experiences/0/companyWebsite": "https://www.fazwaz.com/", "experiences/0/employmentType": "Full-time", "experiences/0/jobDescription": "General Manager | Real Estate Sales & Strategy | Phuket, Thailand |\n\nA results-driven General Manager leading sales performance, team development, and strategic growth in the real estate sector. Focused on building strong teams, maintaining pipeline control, and delivering consistent business results through structured execution and market insight.\n\nKey Responsibilities\n\nLeadership & Team Development\n- Build, lead, and develop a high-performing sales team\n- Create a culture of accountability, professionalism, and consistent results\n- Coach and guide team members to follow proven processes and improve performance\n\nSales Performance & Pipeline Management\n- Maintain full visibility and control over pipeline activity\n- Drive consistent weekly production through structured sales routines\n- Ensure active lead management and strong pipeline growth across the team\n\nPerformance & Coaching\n- Use data to track performance, conversion rates, and productivity\n- Conduct regular performance reviews with clear, actionable feedback\n- Support agents in negotiation to improve deal quality and closing success\n\nSales Strategy & Execution\n- Strengthen deal quality through pricing strategy and market benchmarking\n- Identify pipeline gaps and implement solutions to improve efficiency\n- Ensure consistency from lead stage to closing\n\nBusiness Growth & Market Insight\n- Identify new opportunities through market trends and competitor analysis\n- Support and execute lead-generation and business expansion strategies\n- Oversee recruitment and onboarding to strengthen team capability", "experiences/0/jobLocation": "ภูเก็ต, ประเทศไทย", "experiences/0/jobLocationCountry": "TH", "experiences/0/jobStartedOn": "2-2026", "experiences/0/jobStillWorking": "true", "experiences/0/logo": "https://media.licdn.com/dms/image/v2/D560BAQGcuDDVD0lcrw/company-logo_400_400/B56Zu78hvTKkAY-/0/1768384765591/fazwaz_logo?e=1778112000&v=beta&t=9QfKGEek9YAoY5IF9kOyLUL34l6DCdQchLOJvJ1vZ_g", "experiences/0/title": "General Manager", "experiences/1/companyId": "6443961", "experiences/1/companyIndustry": "Real Estate", "experiences/1/companyLink1": "https://www.linkedin.com/company/fazwaz/", "experiences/1/companyName": "FazWaz", "experiences/1/companySize": "501-1000", "experiences/1/companyUrn": "ur